INSERT INTO `settings` VALUES (1,'Gateway MTN API URL','gw_mtn_api_url','https://ericssonbasicapi1.azure-api.net','URL to Payment Gateway.','Mobile Money Gateways'),(2,'Gateway MTN API Username','gw_mtn_api_username','','API Username to this gateway.','Mobile Money Gateways'),(3,'Gateway MTN API Password','gw_mtn_api_password','','Gateway API Password.','Mobile Money Gateways'),(4,'Gateway MTN Cost of Inbound Payment','gw_mtn_api_cost_of_inbound_payment','50','The cost incurred in receiving payment.','Mobile Money Gateways'),(5,'Gateway MTN Cost of Outbound Payment','gw_mtn_api_cost_of_outbound_payment','50','The cost incurred in sending payment.','Mobile Money Gateways'),(6,'Gateway AIRTEL MM API URL','gw_airtelmoney_api_url','','URL to Payment Gateway.','Airtel Money Mobile Money Gateways'),(7,'Gateway AIRTEL MM API Username','gw_airtelmoney_api_username','','API Username to this gateway.','Airtel Money Mobile Money Gateways'),(8,'Gateway AIRTEL MM API Password','gw_airtelmoney_api_password','','Gateway AIRTEL API Password.','Airtel Money Mobile Money Gateways'),(9,'Gateway AIRTEL Cost of Inbound Payment','gw_airtelmoney_api_cost_of_inbound_payment','','The cost incurred in receiving payment.','Airtel Money Mobile Money Gateways'),(10,'Gateway AIRTEL Cost of Outbound Payment','gw_airtelmoney_api_cost_of_outbound_payment','','The cost incurred in sending payment.','Airtel Money Mobile Money Gateways'),(11,'Email on Requesting Password Reset','email_tmp_pw_reset','Hi {name}\n\nYou have request for a password reset which you can complete by providing the following verification code below: \n{verification_code}\n\nIf you didn\'t request this action, please ignore this email. If you however requested for a password reset, provide the above verification code in the next step so you can complete the reset process.\n\nThank you\n\nRegards','Email sent on password reset request.','Email Template'),(12,'Email on Creating a Merchant User','email_tmp_on_creating_merchant_user','Hi {name}\n\nYour account has been created and below are the initial details. \n\nURL: {url}\nMerchant Account: {merchant_number}\nUsername: {username}\nPassword: {password}\n\nYou will be required to reset this password when you login for the first time.\n\nThank you\n\nRegards','Email sent after creating a new merchant.','Email Template'),(13,'Email on Password Reset Done','email_tmp_on_password_reset_done','Hi {name}\n\nYour password has been reset successfully. Do you recognize this action? If not, please write to support so that your account can be temporarily suspended.\n\nThank you\n\nRegards','Email sent after resetting password.','Email Template'),(14,'Gateway MTN Momo Collections User ID','gw_mtn_api_collections_user_id','cae741ea-f020-48db-8392-436ec51ce005','The MTN Momo Collections User ID.','Mobile Money Gateways'),(15,'Gateway MTN Momo Collections User Key','gw_mtn_api_collections_user_key','a978581f16764719be31e5d1b7abce92','The MTN Momo Collections User Key.','Mobile Money Gateways'),(16,'Gateway MTN Momo Collections Subscription Key','gw_mtn_api_collections_subscription_key','8937d7376f7e4783a4cfab491d5f1d31','The MTN Momo Collections Subscription Key.','Mobile Money Gateways'),(17,'Gateway MTN Momo Disbursement User ID','gw_mtn_api_disbursements_user_id','90f8d6c5-98fd-4bef-9276-ac9785380bc5','The MTN Momo Disbursement User ID.','Mobile Money Gateways'),(18,'Gateway MTN Momo Disbursement User Key','gw_mtn_api_disbursements_user_key','f9b9c5a662444a0a93a12cb1fa187026','The MTN Momo Disbursement User Key.','Mobile Money Gateways'),(19,'Gateway MTN Momo Disbursement Subscription Key','gw_mtn_api_disbursements_subscription_key','06618e0b22ce46e28e904f1c70d62f82','The MTN Momo Disbursement Subscription Key.','Mobile Money Gateways'),(20,'Gateway MTN Momo Base Currency','gw_mtn_api_base_currency','UGX','The MTN Base Currency.','Mobile Money Gateways'),(21,'Gateway MTN Momo Environment','gw_mtn_api_env','mtnuganda','The MTN Base Environment(mtnuganda | Sandbox).','Mobile Money Gateways'),(22,'Revenue Account','revenue_account','1000002','To receive revenue on every transaction earned.','Financial Accounts'),(23,'Float Stock Account','float_stock_account','1000003','To track disbursement float Stock.','Financial Accounts'),(24,'Gateway MTN API URL FOR SANDBOX','gw_mtn_api_url_sandbox','https://sandbox.momodeveloper.mtn.com','URL to Payment Gateway for Sandbox.','Mobile Money Gateways'),(25,'Gateway MTN Momo Collections User ID for Sandbox','gw_mtn_api_collections_user_id_sandbox','53e67d5f-91da-416e-96f5-c4c6fd1993c7','The MTN Momo Collections User ID for Sandbox.','Mobile Money Gateways'),(26,'Gateway MTN Momo Collections User Key for Sandbox','gw_mtn_api_collections_user_key_sandbox','054e714b77274fc2b4f6e3c27dcb95de','The MTN Momo Collections User Key for Sandbox.','Mobile Money Gateways'),(27,'Gateway MTN Momo Collections Subscription Key for Sandbox','gw_mtn_api_collections_subscription_key_sandbox','b09a16db64f64a3eba3e9a39db42395b','The MTN Momo Collections Subscription Key for Sandbox.','Mobile Money Gateways'),(28,'Gateway MTN Momo Disbursement User ID for Sandbox','gw_mtn_api_disbursements_user_id_sandbox','af9d4703-54fc-4763-848b-d655f1d3b9eb','The MTN Momo Disbursement User ID for Sandbox.','Mobile Money Gateways'),(29,'Gateway MTN Momo Disbursement User Key for Sandbox','gw_mtn_api_disbursements_user_key_sandbox','0cdb8caa9ecb48b0a8c1acdee66e7ad3','The MTN Momo Disbursement User Key for Sandbox.','Mobile Money Gateways'),(30,'Gateway MTN Momo Disbursement Subscription Key for Sandbox','gw_mtn_api_disbursements_subscription_key_sandbox','4012fe3411bc4650920ed48331357823','The MTN Momo Disbursement Subscription Key for Sandbox.','Mobile Money Gateways'),(31,'Gateway MTN Momo Base Currency for Sandbox','gw_mtn_api_base_currency_sandbox','EUR','The MTN Base Currency for sandbox.','Mobile Money Gateways'),(32,'Gateway MTN Cost of Inbound Payment Method','gw_mtn_api_cost_of_inbound_payment_method','flat','